#include <stdio.h>
#include <string.h>
#include <mqueue.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <sys/wait.h>
#include <unistd.h>

int main(void) {
    struct mq_attr attr = { .mq_maxmsg = 10, .mq_msgsize = 128 };
    mqd_t mq = mq_open("/kf_mq_multi", O_CREAT | O_RDWR, 0644, &attr);

    pid_t pid = fork();
    if (pid == 0) {
        const char *msg = "Hello from child";
        mq_send(mq, msg, strlen(msg), 0);
        mq_close(mq);
        _exit(0);
    }

    wait(NULL);
    char buf[128];
    unsigned int prio;
    ssize_t n = mq_receive(mq, buf, sizeof(buf), &prio);
    buf[n] = '\0';
    printf("Parent received: %s\n", buf);

    mq_close(mq);
    mq_unlink("/kf_mq_multi");
    return 0;
}

