void example_mq_fork(void) {
    struct mq_attr a = { .mq_maxmsg = 5, .mq_msgsize = 64 };
    mqd_t q = mq_open("/kf_ex_fork", O_CREAT|O_RDWR, 0644, &a);
    if (fork() == 0) {
        mq_send(q, "42", 2, 0); mq_close(q); _exit(0);
    }
    wait(NULL);
    char buf[64]; mq_receive(q, buf, sizeof(buf), NULL);
    buf[2] = '\0';
    printf("Parent got: %s\n", buf);
    mq_close(q); mq_unlink("/kf_ex_fork");
}
